return [
  {
    json: {
      source: 'manual-demo',
      repository: 'gowri/order-workflows',
      branch: 'dev',
      commitSha: 'demo123456789',
      workflowName: 'Order Status Workflow',
      workflowId: 'REPLACE_WITH_DEV_WORKFLOW_ID',
      jestUnitTest: 'PASSED',
      httpMockTest: 'PASSED',
      snapshotTest: 'PASSED',
      snapshotChanged: false,
      managerApproval: 'APPROVED',
      requestedEnvironment: 'staging',
      n8nBaseUrl: 'https://YOUR-N8N-DOMAIN.com',
      n8nApiKey: 'REPLACE_WITH_N8N_API_KEY'
    }
  }
];

const input = $input.first().json;
const body = input.body || input;

return [
  {
    json: {
      source: body.source || 'github-actions',
      repository: body.repository || body.repo || 'unknown/repository',
      branch: body.branch || body.ref || 'unknown',
      commitSha: body.commitSha || body.sha || '',
      workflowName: body.workflowName || 'Unknown Workflow',
      workflowId: body.workflowId || 'REPLACE_WITH_DEV_WORKFLOW_ID',
      jestUnitTest: body.jestUnitTest || body.jest || 'FAILED',
      httpMockTest: body.httpMockTest || body.httpMock || 'FAILED',
      snapshotTest: body.snapshotTest || body.snapshot || 'FAILED',
      snapshotChanged: body.snapshotChanged === true,
      managerApproval: body.managerApproval || 'PENDING',
      requestedEnvironment: body.requestedEnvironment || 'staging',
      n8nBaseUrl: body.n8nBaseUrl || 'https://YOUR-N8N-DOMAIN.com',
      n8nApiKey: body.n8nApiKey || 'REPLACE_WITH_N8N_API_KEY'
    }
  }
];

const ci = $('Normalize GitHub Test Report').first()?.json || $('Sample Real CI Payload').first().json;
const api = $input.first().json;

const isDevBranch = ci.branch === 'dev' || ci.branch === 'refs/heads/dev';
const testsPassed =
  ci.jestUnitTest === 'PASSED' &&
  ci.httpMockTest === 'PASSED' &&
  ci.snapshotTest === 'PASSED' &&
  ci.snapshotChanged === false;

const apiHealthy = !!api && !!api.id;

return [
  {
    json: {
      ...ci,
      apiProductTitle: api.title || null,
      apiHealthy,
      isDevBranch,
      testsPassed,
      versionControlCheck: isDevBranch ? 'VALID_DEV_BRANCH' : 'INVALID_BRANCH',
      ciCdDecision: testsPassed && apiHealthy && isDevBranch ? 'ALLOW_STAGING' : 'BLOCK_DEPLOYMENT'
    }
  }
];

const original = $('Validate CI/CD Rules').first().json;
const deployResult = $input.first().json;

return [
  {
    json: {
      ...original,
      stagingDeploymentResult: deployResult,
      stagingStatus: deployResult.error ? 'STAGING_DEPLOY_FAILED_OR_API_NOT_CONFIGURED' : 'STAGING_DEPLOY_REQUEST_SENT',
      prodPromotionAllowed: !deployResult.error && original.managerApproval === 'APPROVED'
    }
  }
];

const original = $('Staging Deployment Summary').first().json;
const prodResult = $input.first().json;

return [
  {
    json: {
      result: prodResult.error ? 'PROD_DEPLOY_FAILED_OR_API_NOT_CONFIGURED' : 'SUCCESS',
      message: prodResult.error
        ? 'Tests passed and approval was completed, but production API deployment failed. Check n8nBaseUrl, workflowId and API key.'
        : 'Workflow passed Jest, HTTP mock, snapshot, version control checks and was promoted Dev → Staging → Prod.',
      repository: original.repository,
      branch: original.branch,
      commitSha: original.commitSha,
      workflowName: original.workflowName,
      jestUnitTest: original.jestUnitTest,
      httpMockTest: original.httpMockTest,
      snapshotTest: original.snapshotTest,
      snapshotChanged: original.snapshotChanged,
      apiHealthy: original.apiHealthy,
      versionControlCheck: original.versionControlCheck,
      stagingStatus: original.stagingStatus,
      productionDeploymentResult: prodResult
    }
  }
];

return [
  {
    json: {
      result: 'BLOCKED',
      message: 'Deployment blocked. Check Jest, HTTP mock, snapshot, API health, or branch validation.',
      repository: $json.repository,
      branch: $json.branch,
      workflowName: $json.workflowName,
      jestUnitTest: $json.jestUnitTest,
      httpMockTest: $json.httpMockTest,
      snapshotTest: $json.snapshotTest,
      snapshotChanged: $json.snapshotChanged,
      apiHealthy: $json.apiHealthy,
      versionControlCheck: $json.versionControlCheck,
      ciCdDecision: $json.ciCdDecision
    }
  }
];

return [
  {
    json: {
      result: 'APPROVAL_PENDING_OR_REJECTED',
      message: 'Tests passed, but manager approval is not APPROVED. Production promotion stopped.',
      repository: $json.repository,
      branch: $json.branch,
      workflowName: $json.workflowName,
      managerApproval: $json.managerApproval
    }
  }
];

return [
  {
    json: {
      result: 'STAGING_DEPLOYMENT_NOT_CONFIRMED',
      message: 'Staging promotion was not confirmed, so production deployment was stopped.',
      repository: $json.repository,
      workflowName: $json.workflowName,
      stagingStatus: $json.stagingStatus
    }
  }
];
